'use client';

import React, { useState, useEffect, useRef } from 'react';
import { Search, Loader2, Check, ChevronDown } from 'lucide-react';
import { getCourses } from '@/src/services/courseService';

interface Course {
  _id: string;
  name?: string;
  code?: string;
  course_fee?: number;
  license_category_id?: string;
  license_category_name?: string;
}

interface CourseSelectDropdownProps {
  value?: string;
  defaultValue?: string;
  onChange?: (val: string) => void;
  onCourseSelect?: (course: Course | null) => void;
  className?: string;
  placeholder?: string;
  initialCourseName?: string;
  name?: string;
  filters?: Record<string, any>;
}

export default function CourseSelectDropdown({
  value,
  defaultValue = '',
  onChange,
  onCourseSelect,
  className = '',
  placeholder = '-- Chọn khóa học --',
  initialCourseName = '',
  name,
  filters = {},
}: CourseSelectDropdownProps) {
  const [isOpen, setIsOpen] = useState(false);
  const [internalValue, setInternalValue] = useState(defaultValue);
  const [search, setSearch] = useState('');
  const [courses, setCourses] = useState<Course[]>([]);
  const [page, setPage] = useState(1);
  const [hasMore, setHasMore] = useState(true);
  const [isLoading, setIsLoading] = useState(false);
  const [selectedName, setSelectedName] = useState(initialCourseName);

  const dropdownRef = useRef<HTMLDivElement>(null);
  const searchTimeout = useRef<NodeJS.Timeout | null>(null);
  const isFetchingRef = useRef(false);
  const sentinelRef = useRef<HTMLDivElement>(null);

  const fetchCourses = async (p: number, q: string, append = false) => {
    if (isFetchingRef.current) return;
    isFetchingRef.current = true;
    setIsLoading(true);

    try {
      const apiFilters = { search: q, ...filters };
      const res = await getCourses(p, 10, apiFilters);

      if (res.success && res.data) {
        let newDocs: Course[] = [];
        if (Array.isArray(res.data.docs)) newDocs = res.data.docs as Course[];
        else if (Array.isArray(res.data.data)) newDocs = res.data.data as Course[];
        else if (Array.isArray(res.data)) newDocs = res.data as Course[];

        setCourses((prev) => {
          const all = append ? [...prev, ...newDocs] : newDocs;
          const unique = Array.from(new Map(all.map((item: Course) => [item._id, item])).values()) as Course[];
          return unique;
        });

        const totalPages = res.data.meta?.total_pages || res.data.meta?.totalPages || 1;
        setHasMore(p < totalPages);
        setPage(p);
      }
    } catch (err) {
      console.error('Lỗi lấy danh sách khóa học', err);
    } finally {
      setIsLoading(false);
      isFetchingRef.current = false;
    }
  };

  // Infinite Scroll via Intersection Observer
  useEffect(() => {
    if (!isOpen || !hasMore || isLoading) return;

    const observer = new IntersectionObserver(
      (entries) => {
        if (entries[0].isIntersecting && !isFetchingRef.current) {
          fetchCourses(page + 1, search, true);
        }
      },
      { threshold: 0.1, rootMargin: '50px' },
    );

    const currentSentinel = sentinelRef.current;
    if (currentSentinel) observer.observe(currentSentinel);

    return () => {
      if (currentSentinel) observer.unobserve(currentSentinel);
    };
  }, [isOpen, hasMore, isLoading, page, search, filters]);

  // Initial fetch/sync
  useEffect(() => {
    const valObj = value !== undefined ? value : internalValue;
    const shouldFetch = isOpen || (valObj && courses.length === 0 && !selectedName);
    if (shouldFetch && !isFetchingRef.current && courses.length === 0) {
      fetchCourses(1, '');
    }
  }, [isOpen, value, internalValue]);

  // Sync selected name
  useEffect(() => {
    if (initialCourseName && !selectedName) setSelectedName(initialCourseName);
  }, [initialCourseName]);


