    const valObj = value !== undefined ? value : internalValue;
    if (valObj) {
      if (courses.length > 0) {
        const c = courses.find((x) => x._id === valObj);
        if (c) {
          setSelectedName(c.name || c.code || '');
        }
      } else if (initialCourseName) {
        setSelectedName(initialCourseName);
      }
    } else {
      setSelectedName('');
    }
  }, [value, internalValue, courses, initialCourseName]);

  // Click outside closure
  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(e.target as Node)) setIsOpen(false);
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleSearchChange = (val: string) => {
    setSearch(val);
    if (searchTimeout.current) clearTimeout(searchTimeout.current);
    searchTimeout.current = setTimeout(() => {
      setHasMore(true);
      fetchCourses(1, val, false);
    }, 400);
  };

  const handleSelect = (course?: Course) => {
    const newVal = course ? course._id : '';
    if (onChange) onChange(newVal);
    if (onCourseSelect) onCourseSelect(course || null);
    if (value === undefined) {
      setInternalValue(newVal);
    }
    // Set name immediately for immediate UI feedback
    setSelectedName(course ? course.name || course.code || '' : '');
    setIsOpen(false);
  };

  const displayValue = value !== undefined ? value : internalValue;

  return (
    <div className="relative w-full" ref={dropdownRef}>
      {name && <input type="hidden" name={name} value={displayValue} />}

      <div
