        </span>
        <ChevronDown
          className={`w-4 h-4 text-gray-400 transition-transform duration-300 ${isOpen ? 'rotate-180 text-indigo-500' : ''}`}
        />
      </div>

      {isOpen && (
        <div className="absolute top-full left-0 right-0 mt-2 bg-white border border-gray-100 rounded-2xl shadow-xl z-[9999] overflow-hidden animate-in fade-in slide-in-from-top-2 duration-200 min-w-full">
          <div className="p-3 border-b border-gray-50 bg-gray-50/50">
            <div className="relative">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
              <input
                autoFocus
                type="text"
                className="w-full pl-9 pr-3 py-2 bg-white border border-gray-200 rounded-xl text-sm font-medium focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 transition-all outline-none"
                placeholder="Tìm khóa học..."
                value={search}
                onChange={(e) => handleSearchChange(e.target.value)}
              />
            </div>
          </div>

          <div className="max-h-[220px] overflow-y-auto overscroll-contain py-2 bg-white custom-scrollbar">
            <div
              onClick={() => handleSelect(undefined)}
              className={`px-4 py-2.5 flex items-center justify-between cursor-pointer transition-colors ${!displayValue ? 'bg-indigo-50 text-indigo-700 font-bold' : 'text-gray-600 hover:bg-gray-50'}`}
            >
              <span className="text-sm italic">-- Chưa vào khóa --</span>
              {!displayValue && <Check className="w-4 h-4" />}
            </div>

            {courses.length > 0 ? (
              courses.map((c) => (
                <div
                  key={c._id}
                  onClick={() => handleSelect(c)}
                  className={`px-4 py-2.5 flex items-center justify-between cursor-pointer transition-colors ${
                    displayValue === c._id ? 'bg-indigo-50 text-indigo-700 font-bold' : 'text-gray-700 hover:bg-gray-50'
                  }`}
                >
                  <span className="text-sm">{c.name || c.code}</span>
                  {displayValue === c._id && <Check className="w-4 h-4 text-indigo-600" />}
                </div>
              ))
            ) : !isLoading ? (
              <div className="py-8 text-center text-gray-400 text-xs font-semibold italic">Không tìm thấy khóa học</div>
            ) : null}

            {isLoading && (
              <div className="py-4 flex justify-center">
                <Loader2 className="w-5 h-5 text-indigo-500 animate-spin" />
              </div>
            )}

            {/* Sentinel for Infinite Scroll */}
            <div ref={sentinelRef} className="h-1 w-full" />
          </div>
        </div>
      )}
    </div>
  );
}

