const toTimeValue = (value?: string) => {
  if (!value) return undefined;
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return undefined;
  return date.toISOString().slice(11, 16);
};

export const addDatSession = (data: Partial<DatSession>) => {
  const start = data.start_time ? new Date(data.start_time) : null;
  const end = data.end_time ? new Date(data.end_time) : null;
  const duration = start && end ? Math.max(0, Math.round((end.getTime() - start.getTime()) / 60000)) : undefined;

  return apiClient('/dat', {
    method: 'POST',
    body: JSON.stringify({
      enrollmentId: data.course_student_id,
      date: start && !Number.isNaN(start.getTime()) ? start.toISOString().split('T')[0] : undefined,
      timeStart: toTimeValue(data.start_time),
      timeEnd: toTimeValue(data.end_time),
      duration,
      km: data.distance_km,
      notes: data.notes,
    }),
  });
};

